// ============================================================
// HARMONIA LEAD NORMALIZER
// Transforms leads from Google LSA, Facebook, Elementor to unified schema
// ============================================================

const body = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};
const query = $input.first().json.query || {};

let normalized = {
  // Core fields
  name: '',
  firstName: '',
  lastName: '',
  phone: '',
  email: '',

  // Address
  address: '',
  city: '',
  state: '',
  zip: '',

  // Context
  notes: '',
  serviceType: '',
  urgency: 'normal',

  // Metadata
  source: 'unknown',
  sourceDetails: {},
  rawPayload: body,
  receivedAt: new Date().toISOString(),
  ipAddress: headers['x-forwarded-for'] || headers['x-real-ip'] || null
};

// ============================================================
// SOURCE DETECTION & NORMALIZATION
// ============================================================

// 1. GOOGLE LOCAL SERVICES ADS (LSA)
if (body.lead_type === 'MESSAGE' || body.lead_type === 'PHONE_CALL' || body.google_key || body.leadId?.startsWith('google')) {
  normalized.source = 'google_lsa';
  normalized.sourceDetails = {
    leadType: body.lead_type,
    googleKey: body.google_key,
    categoryId: body.category_id
  };

  normalized.name = body.user_name || body.consumer_name || '';
  normalized.phone = body.phone_number || body.consumer_phone_number || '';
  normalized.email = body.email || '';
  normalized.address = body.postal_address || body.job_location?.formatted_address || '';
  normalized.notes = body.text || body.description || '';
  normalized.serviceType = body.category_name || body.service_category || '';

  // LSA often includes city/state in structured format
  if (body.job_location) {
    normalized.city = body.job_location.city || '';
    normalized.state = body.job_location.state || '';
    normalized.zip = body.job_location.postal_code || '';
  }
}

// 2. FACEBOOK LEAD ADS
else if (body.leadgen_id || body.field_data || body.page_id || headers['x-facebook-webhook']) {
  normalized.source = 'facebook_lead';
  normalized.sourceDetails = {
    leadgenId: body.leadgen_id,
    pageId: body.page_id,
    formId: body.form_id,
    adId: body.ad_id,
    adsetId: body.adset_id,
    campaignId: body.campaign_id
  };

  const fields = body.field_data || [];

  // Map Facebook's field_data array to our schema
  for (const field of fields) {
    const name = (field.name || '').toLowerCase();
    const value = field.values?.[0] || '';

    if (name.includes('full') && name.includes('name')) normalized.name = value;
    else if (name === 'first_name' || name === 'firstname') normalized.firstName = value;
    else if (name === 'last_name' || name === 'lastname') normalized.lastName = value;
    else if (name.includes('phone') || name === 'phone_number') normalized.phone = value;
    else if (name.includes('email')) normalized.email = value;
    else if (name.includes('street') || name.includes('address')) normalized.address = value;
    else if (name === 'city') normalized.city = value;
    else if (name === 'state' || name === 'province') normalized.state = value;
    else if (name.includes('zip') || name.includes('postal')) normalized.zip = value;
    else if (name.includes('service') || name.includes('issue') || name.includes('problem')) {
      normalized.notes = value;
      normalized.serviceType = value;
    }
    else if (name.includes('message') || name.includes('comment')) normalized.notes = value;
  }
}

// 3. ELEMENTOR FORMS
else if (body.form_id || body.form_name || headers['x-elementor-webhook'] || body.fields) {
  normalized.source = 'elementor_form';
  normalized.sourceDetails = {
    formId: body.form_id,
    formName: body.form_name,
    postId: body.post_id,
    referrer: body.referrer || body.referer_title
  };

  const fields = body.fields || body;

  normalized.name = fields.name || fields.full_name || fields.fullname || '';
  normalized.firstName = fields.first_name || fields.firstname || '';
  normalized.lastName = fields.last_name || fields.lastname || '';
  normalized.phone = fields.phone || fields.telephone || fields.tel || fields.mobile || '';
  normalized.email = fields.email || fields.email_address || '';
  normalized.address = fields.address || fields.street || fields.street_address || '';
  normalized.city = fields.city || '';
  normalized.state = fields.state || fields.province || '';
  normalized.zip = fields.zip || fields.zipcode || fields.postal_code || fields.postcode || '';
  normalized.notes = fields.message || fields.comments || fields.notes || fields.service_needed || fields.issue || '';
  normalized.serviceType = fields.service || fields.service_type || fields.service_needed || '';
}

// 4. GENERIC / ZAPIER / CUSTOM WEBHOOKS
else {
  normalized.source = 'webhook_generic';

  // Try common field names
  normalized.name = body.name || body.full_name || body.customer_name || '';
  normalized.firstName = body.first_name || body.firstName || '';
  normalized.lastName = body.last_name || body.lastName || '';
  normalized.phone = body.phone || body.phone_number || body.phoneNumber || body.mobile || '';
  normalized.email = body.email || body.email_address || '';
  normalized.address = body.address || body.street_address || body.street || '';
  normalized.city = body.city || '';
  normalized.state = body.state || '';
  normalized.zip = body.zip || body.zipcode || body.postal_code || '';
  normalized.notes = body.message || body.notes || body.comments || body.description || '';
  normalized.serviceType = body.service || body.service_type || '';
}

// ============================================================
// POST-PROCESSING
// ============================================================

// Clean phone number to E.164 format
if (normalized.phone) {
  let phone = normalized.phone.replace(/\D/g, '');
  if (phone.length === 10) {
    phone = '+1' + phone;
  } else if (phone.length === 11 && phone.startsWith('1')) {
    phone = '+' + phone;
  } else if (phone.length > 0 && !phone.startsWith('+')) {
    phone = '+' + phone;
  }
  normalized.phone = phone;
}

// Build name from parts if full name not provided
if (!normalized.name && (normalized.firstName || normalized.lastName)) {
  normalized.name = `${normalized.firstName} ${normalized.lastName}`.trim();
}

// Extract name parts if only full name provided
if (normalized.name && !normalized.firstName) {
  const parts = normalized.name.trim().split(/\s+/);
  normalized.firstName = parts[0] || '';
  normalized.lastName = parts.slice(1).join(' ') || '';
}

// Build full address string if parts exist but full doesn't
if (!normalized.address && (normalized.city || normalized.state || normalized.zip)) {
  normalized.address = [normalized.city, normalized.state, normalized.zip].filter(Boolean).join(', ');
}

// Detect urgency from notes
const notesLower = normalized.notes.toLowerCase();
const emergencyKeywords = ['no heat', 'no cooling', 'no ac', 'not working', 'broken', 'emergency', 'urgent', 'asap', 'today', 'freezing', 'smoke', 'gas smell', 'water leak', 'flooded'];

if (emergencyKeywords.some(kw => notesLower.includes(kw))) {
  normalized.urgency = 'emergency';
}

return { json: normalized };

// ============================================================
// HARMONIA LEAD SCORING ENGINE
// Assigns value 1-100 based on multiple weighted factors
// ============================================================

const lead = $input.first().json;

// Base score
let score = 50;
const factors = {};

const notesLower = (lead.notes || '').toLowerCase();
const serviceLower = (lead.serviceType || '').toLowerCase();

// ============================================================
// FACTOR 1: HOMEOWNER STATUS (+20 / -10)
// ============================================================
const homeownerKeywords = ['owner', 'homeowner', 'my house', 'my home', 'we own', 'i own', 'our home'];
const renterKeywords = ['renting', 'tenant', 'landlord', 'apartment', 'lease', 'property manager'];

const isHomeowner = homeownerKeywords.some(kw => notesLower.includes(kw));
const isRenter = renterKeywords.some(kw => notesLower.includes(kw));

if (isHomeowner) {
  score += 20;
  factors.homeowner = { bonus: 20, detected: 'homeowner' };
} else if (isRenter) {
  score -= 10;
  factors.homeowner = { bonus: -10, detected: 'renter' };
} else {
  factors.homeowner = { bonus: 0, detected: 'unknown' };
}

// ============================================================
// FACTOR 2: SYSTEM AGE (+15 for old systems = replacement potential)
// ============================================================
const ageKeywords = ['old', 'years old', '10 year', '15 year', '20 year', 'original', 'builder grade', 'ancient', 'outdated'];
const hasOldSystem = ageKeywords.some(kw => notesLower.includes(kw));

if (hasOldSystem) {
  score += 15;
  factors.systemAge = { bonus: 15, detected: 'old_system' };
} else {
  factors.systemAge = { bonus: 0, detected: 'unknown' };
}

// ============================================================
// FACTOR 3: EMERGENCY (+25 - highest urgency)
// ============================================================
const emergencyKeywords = [
  'no heat', 'no cooling', 'no ac', 'not working', 'broken', 'stopped working',
  'emergency', 'urgent', 'asap', 'today', 'right now', 'immediately',
  'freezing', 'sweating', 'too hot', 'too cold',
  'water leak', 'gas smell', 'smoke', 'burning smell', 'electrical smell'
];

const isEmergency = emergencyKeywords.some(kw => notesLower.includes(kw)) || lead.urgency === 'emergency';

if (isEmergency) {
  score += 25;
  factors.emergency = { bonus: 25, detected: true };
} else {
  factors.emergency = { bonus: 0, detected: false };
}

// ============================================================
// FACTOR 4: SERVICE TYPE VALUE (+5 to +20)
// ============================================================
const highValueServices = ['replacement', 'install', 'new unit', 'new system', 'upgrade', 'change out', 'changeout'];
const mediumValueServices = ['repair', 'fix', 'diagnostic', 'not cooling', 'not heating'];
const lowValueServices = ['tune up', 'tune-up', 'maintenance', 'cleaning', 'filter'];

const combinedService = notesLower + ' ' + serviceLower;

if (highValueServices.some(kw => combinedService.includes(kw))) {
  score += 20;
  factors.serviceValue = { bonus: 20, detected: 'high_value' };
} else if (mediumValueServices.some(kw => combinedService.includes(kw))) {
  score += 10;
  factors.serviceValue = { bonus: 10, detected: 'medium_value' };
} else if (lowValueServices.some(kw => combinedService.includes(kw))) {
  score += 5;
  factors.serviceValue = { bonus: 5, detected: 'low_value' };
} else {
  factors.serviceValue = { bonus: 0, detected: 'unknown' };
}

// ============================================================
// FACTOR 5: TIME OF DAY (+5 for business hours)
// ============================================================
const hour = new Date().getHours();
const isBusinessHours = hour >= 8 && hour <= 18;

if (isBusinessHours) {
  score += 5;
  factors.timing = { bonus: 5, detected: 'business_hours' };
} else {
  factors.timing = { bonus: 0, detected: 'after_hours' };
}

// ============================================================
// FACTOR 6: LEAD SOURCE QUALITY
// ============================================================
const sourceScores = {
  'google_lsa': 15,        // High intent - searched for service
  'google_ads': 12,        // Good intent
  'elementor_form': 10,    // Website visitor - decent intent
  'facebook_lead': 5,      // Lower intent - passive scroll
  'referral': 20,          // Highest quality
  'webhook_generic': 5     // Unknown quality
};

const sourceBonus = sourceScores[lead.source] || 5;
score += sourceBonus;
factors.source = { bonus: sourceBonus, detected: lead.source };

// ============================================================
// FACTOR 7: CONTACT INFO COMPLETENESS (+10)
// ============================================================
const hasPhone = lead.phone && lead.phone.length >= 10;
const hasEmail = lead.email && lead.email.includes('@');
const hasAddress = lead.address && lead.address.length > 10;

let contactBonus = 0;
if (hasPhone && hasEmail && hasAddress) {
  contactBonus = 10;
} else if (hasPhone && hasAddress) {
  contactBonus = 7;
} else if (hasPhone) {
  contactBonus = 3;
}

score += contactBonus;
factors.contactInfo = { 
  bonus: contactBonus, 
  hasPhone: hasPhone,
  hasEmail: hasEmail,
  hasAddress: hasAddress
};

// ============================================================
// NORMALIZE & CLASSIFY
// ============================================================

// Cap score at 1-100
score = Math.max(1, Math.min(100, Math.round(score)));

// Determine tier
let tier, tierDescription;
if (score >= 85) {
  tier = 'HOT';
  tierDescription = 'High-value lead, immediate action required';
} else if (score >= 70) {
  tier = 'WARM';
  tierDescription = 'Good lead, prioritize follow-up';
} else if (score >= 50) {
  tier = 'COOL';
  tierDescription = 'Standard lead, normal follow-up';
} else {
  tier = 'COLD';
  tierDescription = 'Low-value lead, nurture sequence';
}

// Determine action
let recommendedAction;
if (isEmergency) {
  recommendedAction = 'IMMEDIATE_CALL';
} else if (tier === 'HOT') {
  recommendedAction = 'PRIORITY_CALL';
} else if (tier === 'WARM') {
  recommendedAction = 'STANDARD_CALL';
} else {
  recommendedAction = 'SMS_FIRST';
}

return {
  json: {
    ...lead,
    scoring: {
      score: score,
      tier: tier,
      tierDescription: tierDescription,
      isEmergency: isEmergency,
      recommendedAction: recommendedAction,
      factors: factors,
      calculatedAt: new Date().toISOString()
    }
  }
};

